+import type { World } from '../world';
+import type { Predicate, QueryInstance } from './types';
+import { checkQueryStatic } from './utils/check-query';
+
+type Pending = { depth: number; entries: Map<QueryInstance, Set<Entity>> };
+const pendingByWorld = new WeakMap<World, Pending>();
+
+export function predicateMatches(world: World, entity: Entity, predicate: Predicate): boolean {
+    const values: unknown[] = [];
+    for (const trait of predicate.traits) {
+        if (!hasTrait(world, entity, trait)) return false;
+        values.push(getTrait(world, entity, trait));
+    }
+    return predicate.callback(values as never);
+}
+
+export function matchesPredicateFilters(world: World, query: QueryInstance, entity: Entity): boolean {
+    for (const predicate of query.predicates) if (!predicateMatches(world, entity, predicate)) return false;
+    for (const predicate of query.notPredicates) if (predicateMatches(world, entity, predicate)) return false;
+    if (query.orPredicates.length > 0) {
+        let matches = false;
+        for (const predicate of query.orPredicates) {
+            if (predicateMatches(world, entity, predicate)) {
+                matches = true;
+                break;
+            }
+        }
+        if (!matches && query.traitInstances.or.length === 0) return false;
+    }
+    return true;
+}
+
+function matchesRelations(world: World, query: QueryInstance, entity: Entity): boolean {
+    for (const pair of query.relationFilters ?? []) if (!hasRelationPair(world, entity, pair)) return false;
+    return true;
+}
+
+function refreshQuery(world: World, query: QueryInstance, entity: Entity) {
+    if (query.predicateTrackers.length > 0) {
+        const baseMatches = checkQueryStatic(world, query, entity) && matchesRelations(world, query, entity);
+        for (const tracker of query.predicateTrackers) {
+            const now = baseMatches && predicateMatches(world, entity, tracker.predicate);
+            const previous = tracker.matches.get(entity) ?? false;
+            tracker.matches.set(entity, now);
+            if (tracker.type === 'add') {
+                if (!previous && now) query.add(entity);
+                else if (previous && !now) query.remove(world, entity);
+            } else if (tracker.type === 'remove') {
+                if (previous && !now) query.add(entity);
+                else if (!previous && now) query.remove(world, entity);
+            } else if (previous !== now) {
+                query.add(entity);
+            }
+        }
+        return;
+    }
+
+    const matches = checkQueryStatic(world, query, entity) && matchesPredicateFilters(world, query, entity) && matchesRelations(world, query, entity);
+    if (matches) query.add(entity);
+    else query.remove(world, entity);
+}
+
+export function updatePredicateQueries(world: World, instance: TraitInstance, entity: Entity) {
+    const pending = pendingByWorld.get(world);
+    for (const query of instance.predicateQueries) {
+        if (pending?.depth) {
+            let entities = pending.entries.get(query);
+            if (!entities) pending.entries.set(query, (entities = new Set()));
+            entities.add(entity);
+        } else {
+            refreshQuery(world, query, entity);
+        }
+    }
+}
+
+export function beginPredicateUpdates(world: World) {
+    let pending = pendingByWorld.get(world);
+    if (!pending) pendingByWorld.set(world, (pending = { depth: 0, entries: new Map() }));
+    pending.depth++;
+}
+
+export function endPredicateUpdates(world: World) {
+    const pending = pendingByWorld.get(world);
+    if (!pending || --pending.depth) return;
+    for (const [query, entities] of pending.entries) for (const entity of entities) refreshQuery(world, query, entity);
+    pending.entries.clear();
+}
